export abstract class BaseAPIResource {
  protected _client: BaseAnthropic;
  protected _retries: number;

  constructor(client: BaseAnthropic, retries = 2) {
    this._client = client;
    this._retries = retries;
  }
}

export class Messages extends BaseAPIResource {
  create(body: MessageCreateParams, options?: RequestOptions): APIPromise<Message> {
    return this._client.post('/v1/messages', { body, ...options });
  }
}
